"""Base classes for sklearn estimators."""
import numpy as np


# ─── Defensive safe defaults for upstream-sklearn attributes ───────
#
# The iOS sklearn shim is a from-scratch reimplementation of ~40 of
# upstream's most-used modules, so individual classes don't populate
# every upstream post-fit attribute. Downstream libraries that walk
# estimator state (Optuna, MLflow, scikit-multilearn, eli5, shap)
# crash with AttributeError on attributes the shim didn't think to
# set. Per-class patching this for ~350 classes is unbounded work;
# a default-via-``__getattr__`` on ``BaseEstimator`` covers them all
# at once.
#
# Each set below is the upstream attribute name → kind of default
# we want when fit() didn't populate it. Picking the right "type"
# matters: ``len(svc.support_)`` needs an iterable (so empty array,
# not None); ``acc = est.best_score_`` needs a float; ``cm.fit_status_``
# needs an int. The categorisation matches upstream sklearn's
# documented post-fit attribute types.

# Empty 1-D numpy arrays — class labels, coefficients, feature
# importances, support indices, anything iterable per-sample.
_SK_EMPTY_1D = frozenset({
    'classes_', 'coef_', 'intercept_', 'feature_importances_',
    'labels_', 'support_', 'n_support_', 'transduction_',
    'class_prior_', 'class_count_', 'priors_', 'singular_values_',
    'explained_variance_', 'explained_variance_ratio_',
    'noise_variance_', 'feature_names_in_', 'sigma_', 'var_',
    'theta_', 'epsilon_', 'classes_count_', 'class_log_prior_',
    'feature_log_prob_', 'category_count_', 'feature_count_',
    'oob_decision_function_', 'oob_prediction_',
    'predecessor_', 'reachability_', 'ordering_',
    'pvalues_', 'scores_',
})

# Empty 2-D numpy matrices — centers, support vectors, components,
# means, covariances per cluster/class etc.
_SK_EMPTY_2D = frozenset({
    'cluster_centers_', 'support_vectors_', 'means_', 'covariances_',
    'components_', 'scalings_', 'label_distributions_', 'dual_coef_',
    'weights_', 'precisions_', 'precisions_cholesky_',
    'rotations_', 'X_train_', 'covariance_', 'location_',
    'embedding_', 'affinity_matrix_', 'graph_',
})

# Integer scalars — counts of iterations, features, classes, etc.
_SK_INT_ZERO = frozenset({
    'n_iter_', 'n_features_in_', 'n_classes_', 'n_features_',
    'n_components_', 'n_outputs_', 'n_clusters_', 'n_layers_',
    'n_leaves_', 'n_outliers_', 'n_inliers_', 'n_samples_seen_',
    'fit_status_', 'best_iter_',
})

# Float scalars — losses, divergences, scores, errors.
_SK_FLOAT_ZERO = frozenset({
    'inertia_', 'loss_', 'kl_divergence_', 'stress_',
    'reconstruction_error_', 'reconstruction_err_',
    'lower_bound_', 'oob_score_', 'best_score_',
    'score_', 'tol_', 'mse_', 'mae_', 'r2_',
})

# Boolean — convergence / fit flags. Default True is safer: code
# typically does ``if est.converged_: …`` and we want the happy
# path; closed-form solvers that don't iterate are arguably
# "converged" in zero steps.
_SK_BOOL_TRUE = frozenset({
    'converged_', 'is_fitted_',
})

# Empty lists — collections of sub-estimators / steps / coefs.
_SK_EMPTY_LIST = frozenset({
    'estimators_', 'calibrated_classifiers_', 'steps',
    'loss_curve_', 'coefs_', 'intercepts_', 'history_',
    'cv_results_', 'best_estimator_indices_',
    'estimator_errors_', 'estimator_weights_',
})

# None — opaque object handles where callers explicitly check
# ``is None`` before using.
_SK_NONE = frozenset({
    'tree_', 'best_estimator_', 'best_params_',
    'core_sample_indices_', 'mean_',
    'random_state_', 'effective_n_jobs_',
    'partial_fit_estimator_', 'kernel_', 'base_estimator_',
})


class _MissingSentinel:
    """Distinguishable from any legitimate sklearn value (None / 0 /
    empty array / etc) — used by ``_sk_safe_default`` to signal
    "this name isn't in our coverage; raise AttributeError"."""
    __slots__ = ()
_MISSING = _MissingSentinel()


def _sk_safe_default(name):
    """Resolve a known upstream-sklearn attribute name to a typed
    safe default. Returns sentinel ``_MISSING`` if the name isn't
    in any of our coverage sets (caller raises AttributeError)."""
    if name in _SK_EMPTY_1D:    return np.array([])
    if name in _SK_EMPTY_2D:    return np.empty((0, 0))
    if name in _SK_INT_ZERO:    return 0
    if name in _SK_FLOAT_ZERO:  return 0.0
    if name in _SK_BOOL_TRUE:   return True
    if name in _SK_EMPTY_LIST:  return []
    if name in _SK_NONE:        return None
    return _MISSING


class BaseEstimator:
    def get_params(self, deep=True):
        import inspect
        init = self.__class__.__init__
        params = inspect.signature(init).parameters
        return {k: getattr(self, k) for k in params if k != 'self' and hasattr(self, k)}

    def set_params(self, **params):
        for k, v in params.items():
            setattr(self, k, v)
        return self

    def __getattr__(self, name):
        """Defensive default for missing upstream sklearn attributes.

        Called by Python only when normal attribute lookup fails —
        i.e. when ``self.__dict__`` and the class hierarchy don't
        have ``name``. Returns a typed safe default for the ~80
        upstream attributes downstream code commonly reads after
        fit(). Unknown / typo'd names still raise AttributeError so
        real bugs in user code surface.

        Excludes leading-underscore names: those matter for Python's
        introspection (pickling, copy, abstract-method machinery,
        coroutine internals) and intercepting them via ``__getattr__``
        produces obscure breakage. Pure attribute defaults only."""
        if name.startswith('_'):
            raise AttributeError(
                f"{type(self).__name__!r} object has no attribute {name!r}")
        default = _sk_safe_default(name)
        if default is _MISSING:
            raise AttributeError(
                f"{type(self).__name__!r} object has no attribute {name!r}")
        return default


class ClassifierMixin:
    def score(self, X, y):
        return np.mean(self.predict(X) == np.asarray(y))


class RegressorMixin:
    def score(self, X, y):
        y = np.asarray(y, dtype=float)
        y_pred = self.predict(X)
        ss_res = np.sum((y - y_pred) ** 2)
        ss_tot = np.sum((y - np.mean(y)) ** 2)
        return 1.0 - ss_res / max(ss_tot, 1e-15)


class TransformerMixin:
    def fit_transform(self, X, y=None):
        return self.fit(X, y).transform(X)


def clone(estimator):
    """Create an unfitted clone of an estimator (like sklearn.base.clone)."""
    import copy
    klass = type(estimator)
    # Get only the shallow (constructor-level) params, not nested ones
    params = estimator.get_params(deep=False)
    new_est = klass(**params)
    return new_est


# ─── Stub base for upstream-only estimator classes ─────────────────


class _StubEstimator:
    """Permissive estimator base used by the auto-generated stubs
    (RFE, RFECV, SelectFdr, …). Records constructor args + kwargs;
    fit/transform/predict return sensible defaults (self, the input,
    or zeros) so calling code doesn't crash.

    Accepts positional args because many real sklearn classes wrap
    a base estimator passed positionally — e.g. ``RFE(LogisticRegression(),
    n_features_to_select=3)``. Storing them as ``self._args`` keeps
    them available for downstream introspection without changing the
    stub's behaviour (which is to be inert)."""

    def __init__(self, *args, **kwargs):
        self._args = args
        # First positional arg of most wrapper estimators (RFE / RFECV
        # / OneVsRest / CalibratedClassifierCV etc.) is conventionally
        # called ``estimator``. Expose it under that name when there's
        # a single positional arg so downstream callers that read
        # ``self.estimator`` (very common pattern in sklearn) work
        # without us having to subclass per-wrapper.
        if len(args) == 1 and 'estimator' not in kwargs:
            self.estimator = args[0]
        for k, v in kwargs.items():
            setattr(self, k, v)

    def fit(self, X, y=None, **kwargs):
        try:
            import numpy as _np
            X = _np.asarray(X)
            self.n_features_in_ = X.shape[1] if X.ndim > 1 else 1
        except Exception:
            pass
        return self

    def fit_transform(self, X, y=None, **kwargs):
        self.fit(X, y, **kwargs)
        return self.transform(X)

    def transform(self, X):
        import numpy as _np
        return _np.asarray(X)

    def predict(self, X):
        import numpy as _np
        X = _np.asarray(X)
        return _np.zeros(len(X))

    def predict_proba(self, X):
        import numpy as _np
        X = _np.asarray(X)
        return _np.full((len(X), 2), 0.5)

    def score(self, X, y, **kwargs):
        return 0.0

    def get_params(self, deep=True):
        return {k: v for k, v in vars(self).items() if not k.startswith('_')}

    def set_params(self, **params):
        for k, v in params.items():
            setattr(self, k, v)
        return self



