def check_array(*a, **kw):
    """Validate the array. Stub returns first arg unchanged."""
    if a: return a[0]
    return None


def check_is_fitted(estimator, *a, **kw):
    """Stub: assume estimator is fitted."""
    return None


def config_context(**kw):
    """Context manager for sklearn config — no-op."""
    class _CM:
        def __enter__(self):  return self
        def __exit__(self, *a): return False
    return _CM()


def get_config():
    """Return the sklearn config dict."""
    return {}


def estimator_html_repr(est):
    """Return an HTML representation — stub returns a simple string."""
    return f"<{type(est).__name__}>"


def is_pandas_na(x):
    """Whether ``x`` is the pandas NA singleton."""
    return False


def is_scalar_nan(x):
    """Whether ``x`` is a scalar NaN."""
    try:
        import math
        return isinstance(x, float) and math.isnan(x)
    except Exception:
        return False


def validate_parameter_constraints(constraints, params, caller_name):
    """No-op param-constraint validator."""
    return None


